/**
 * Drizzle Kit Configuration
 *
 * Configuration for database migrations and schema management.
 * Used by drizzle-kit commands: generate, migrate, push, studio
 *
 * @see https://orm.drizzle.team/kit-docs/config-reference
 */

import { defineConfig } from 'drizzle-kit';

export default defineConfig({
  // Schema location - all tables exported from index
  schema: './src/lib/db/schema/index.ts',

  // Output directory for generated migrations
  out: './drizzle',

  // Database dialect
  dialect: 'postgresql',

  // Database connection
  dbCredentials: {
    url: process.env['DATABASE_URL'] ?? 'postgresql://mms:mms@localhost:5432/mms_dev',
  },

  // Verbose output for debugging
  verbose: true,

  // Strict mode - fail on warnings
  strict: true,

  // Breakpoints in generated SQL for transaction safety
  breakpoints: true,

  // Introspection settings
  introspect: {
    casing: 'camel', // Convert snake_case to camelCase
  },

  // Migration settings
  migrations: {
    table: '__drizzle_migrations',
    schema: 'public',
  },
});

/**
 * MMS Database Connection
 *
 * PostgreSQL connection pool using postgres.js driver with Drizzle ORM.
 * Configured for production use with health checks and connection limits.
 *
 * Environment Variables:
 * - DATABASE_URL: PostgreSQL connection string (required)
 * - DATABASE_MAX_CONNECTIONS: Max pool size (default: 20)
 * - DATABASE_SSL: Enable SSL (default: true in production)
 *
 * @see specs/008-operations-deployment.md for production configuration
 */

import { drizzle } from 'drizzle-orm/postgres-js';
import postgres from 'postgres';
import * as schema from './schema';

/**
 * Database configuration from environment
 */
const config = {
  url: process.env['DATABASE_URL'] ?? 'postgresql://mms:mms@localhost:5432/mms_dev',
  maxConnections: parseInt(process.env['DATABASE_MAX_CONNECTIONS'] ?? '20', 10),
  ssl: process.env['DATABASE_SSL'] === 'true' || process.env['NODE_ENV'] === 'production',
  idleTimeout: 20, // seconds
  connectTimeout: 10, // seconds
};

/**
 * PostgreSQL connection pool
 *
 * Using postgres.js for:
 * - Native ESM support
 * - Excellent TypeScript support
 * - Prepared statements
 * - Connection pooling
 */
export const sql = postgres(config.url, {
  max: config.maxConnections,
  idle_timeout: config.idleTimeout,
  connect_timeout: config.connectTimeout,
  ssl: config.ssl ? { rejectUnauthorized: false } : false,
  // Prepare statements for better performance
  prepare: true,
  // Transform column names from snake_case to camelCase
  // Note: Drizzle handles this, so we keep original names
  transform: {
    undefined: null,
  },
  // Connection event handlers for logging/monitoring
  onnotice: () => {
    // Suppress notices in production
  },
});

/**
 * Drizzle ORM instance
 *
 * Provides type-safe query builder with full schema awareness.
 * All queries automatically use the connection pool.
 */
export const db = drizzle(sql, {
  schema,
  logger: process.env['NODE_ENV'] === 'development',
});

/**
 * Database health check
 *
 * Use this for liveness/readiness probes in Kubernetes.
 * Returns true if the database is reachable and responsive.
 */
export async function checkDatabaseHealth(): Promise<boolean> {
  try {
    const result = await sql`SELECT 1 as health`;
    return result.length === 1 && result[0]?.health === 1;
  } catch {
    return false;
  }
}

/**
 * Graceful shutdown
 *
 * Close all database connections gracefully.
 * Call this during application shutdown.
 */
export async function closeDatabaseConnection(): Promise<void> {
  await sql.end();
}

/**
 * Database transaction helper
 *
 * Executes a function within a database transaction.
 * Automatically commits on success or rolls back on error.
 *
 * @example
 * const result = await withTransaction(async (tx) => {
 *   await tx.insert(trains).values({ ... });
 *   await tx.insert(pmSchedule).values({ ... });
 *   return { success: true };
 * });
 */
export type Transaction = Parameters<Parameters<typeof db.transaction>[0]>[0];

export async function withTransaction<T>(
  fn: (tx: Transaction) => Promise<T>
): Promise<T> {
  return db.transaction(async (tx) => fn(tx));
}

// Export types for use in services
export type Database = typeof db;

